    "how_to_use": "Điền {REQUIREMENT} với yêu cầu chức năng, {CONTEXT} (tuỳ chọn).",
    "disabled": false,
    "created_at": "2026-04-02T10:00:00Z",
    "updated_at": "2026-04-02T10:00:00Z"
